const body = $input.first().json.body || {};
const query = $input.first().json.query || {};

const symbol = (body.symbol || query.symbol || 'ETHUSDT').toUpperCase();
const userRisk = body.userRiskPercent || 2;
const minConfidence = body.minConfidence || 0.65;

return [{ json: { symbol, userRisk, minConfidence } }];

const items = $input.all();
const inputData = items.find(i => i.json.symbol)?.json || {};
const symbol = inputData.symbol || 'ETHUSDT';

function parse(data) {
  return data.map(c => ({
    open: parseFloat(c[1]), high: parseFloat(c[2]),
    low: parseFloat(c[3]), close: parseFloat(c[4]), volume: parseFloat(c[5])
  }));
}

function analyze(candles) {
  if (!candles || candles.length < 20) return { direction: 'NEUTRAL', score: 0, rsi: 50 };

  const c = candles[candles.length - 1];
  let bull = 0, bear = 0;

  const avgV = candles.slice(-20).reduce((s, x) => s + x.volume, 0) / 20;
  if (c.volume > avgV * 1.5) c.close > c.open ? bull += 2 : bear += 2;

  const body = Math.abs(c.close - c.open);
  const range = c.high - c.low;
  if (range > 0 && body / range > 0.7) c.close > c.open ? bull += 3 : bear += 3;

  const lower = Math.min(c.open, c.close) - c.low;
  const upper = c.high - Math.max(c.open, c.close);
  if (lower > body * 2) bull += 2;
  if (upper > body * 2) bear += 2;

  let gains = [], losses = [];
  for (let i = Math.max(1, candles.length - 14); i < candles.length; i++) {
    const d = candles[i].close - candles[i-1].close;
    d > 0 ? gains.push(d) : losses.push(-d);
  }
  const avgG = gains.length ? gains.reduce((a,b)=>a+b,0)/14 : 0;
  const avgL = losses.length ? losses.reduce((a,b)=>a+b,0)/14 : 0;
  const rsi = 100 - (100 / (1 + avgG/(avgL||1)));
  if (rsi < 30) bull += 2; else if (rsi > 70) bear += 2;

  const ema9 = candles.slice(-9).reduce((s, x) => s + x.close, 0) / 9;
  const ema21 = candles.slice(-21).reduce((s, x) => s + x.close, 0) / 21;
  if (ema9 > ema21) bull += 2; else bear += 2;

  const total = bull + bear;
  let dir = 'NEUTRAL';
  if (bull > bear * 1.3 && total > 4) dir = 'LONG';
  else if (bear > bull * 1.3 && total > 4) dir = 'SHORT';

  return { direction: dir, score: Math.max(bull, bear), rsi: Math.round(rsi) };
}

function analyzeOB(ob) {
  if (!ob?.bids || !ob.asks) return { direction: 'NEUTRAL', score: 0, spread: 0 };
  const bid1 = parseFloat(ob.bids[0][1]);
  const ask1 = parseFloat(ob.asks[0][1]);
  const dom = (bid1 - ask1) / (bid1 + ask1);
  const score = dom > 0.3 ? 3 : dom > 0.1 ? 1 : dom < -0.3 ? -3 : dom < -0.1 ? -1 : 0;
  const bestBid = parseFloat(ob.bids[0][0]);
  const bestAsk = parseFloat(ob.asks[0][0]);
  const spread = ((bestAsk - bestBid) / ((bestAsk + bestBid) / 2) * 100);
  return { direction: score > 0 ? 'LONG' : score < 0 ? 'SHORT' : 'NEUTRAL', score: Math.abs(score), spread: spread.toFixed(4) };
}

// Найти данные
let c1m = [], c5m = [], c1h = [], ob = {}, price = null;
for (const item of items) {
  if (item.json[0]?.[1]) c1m = parse(item.json);
  else if (item.json[0]?.[4]) {
    if (c1m.length === 0) c1m = parse(item.json);
    else if (c5m.length === 0) c5m = parse(item.json);
  }
  if (item.json.bids) ob = item.json;
  if (item.json.price) price = parseFloat(item.json.price);
}

const a1m = analyze(c1m);
const a5m = analyze(c5m);
const a1h = analyze(c1h);
const aob = analyzeOB(ob);

const dirs = [a1m.direction, a5m.direction, a1h.direction, aob.direction];
const longs = dirs.filter(d => d === 'LONG').length;
const shorts = dirs.filter(d => d === 'SHORT').length;

let finalDir = 'WAIT';
let conf = 0;
if (longs >= 2) { finalDir = 'LONG'; conf = Math.min(0.85, 0.5 + longs * 0.12); }
else if (shorts >= 2) { finalDir = 'SHORT'; conf = Math.min(0.85, 0.5 + shorts * 0.12); }

const minConf = inputData.minConfidence || 0.65;
const shouldTrade = finalDir !== 'WAIT' && conf >= minConf;

return [{ json: {
  symbol,
  currentPrice: price,
  analysis: { '1m': a1m, '5m': a5m, '1h': a1h, orderbook: aob },
  final: { direction: finalDir, confidence: Math.round(conf * 100) / 100 },
  riskManagement: {
    shouldTrade,
    action: shouldTrade ? `Открыть ${finalDir}` : 'Подождать',
    reason: conf < minConf ? `Уверенность ${Math.round(conf*100)}% < ${minConf*100}%` : ''
  },
  timestamp: new Date().toISOString()
} }];
